challenge.solution:
from contextlib import contextmanager

@contextmanager
def temp_dir(d, key):
  original = d.get(key)
  d[key] = 'temp_value'
  try:
    yield d
  finally:
    if original is None:
      del d[key]
    else:
      d[key] = original
